3_real_world_example.code:
async function getData() {
  const response = await fetch('https://dummyjson.com/products/1');

  // 1. The Response Object (headers, status, but body is unread)
  console.log(typeof response); // 'object' (Response instance)

  // 2. The magic conversion step
  const data = await response.json(); // Reads stream AND parses JSON

  // 3. The usable JS Object
  console.log(typeof data);     // 'object' (Plain JS Object)
  console.log(data.title);      // 'Essence Mascara Lash Princess'
}

// Sending JSON requires the reverse process: Object -> String
async function sendData() {
  const newProduct = { title: 'Laptop', price: 999 };
  await fetch('/api/add', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(newProduct) // Assembling back into a flat box
  });
}

